    return "skip";
}

// Parse a Tier
function searchTier(tier){
	_pattern_tier = new RegExp(tier);
	_pattern_tarif = new RegExp("("+tier+")\\s+(\\d+)\\s+(\\d+)\\s+([\\d.]+)");

	sH = javelin.getScreenHeight();
	sW = javelin.getScreenWidth();

	for(i=0; i<sH; i++){
		line = javelin.getString(0, i, sW);
		//log.warning("***"+line+"***");
		if(line.search(_pattern_tier) !== -1){
			log.debug("MATCH FOUND #"+i);
			log.debug("***"+line+"***");
			[, tier, de, a, tarif] = line.match(_pattern_tarif);
			return {"Tier": tier, "de": de, "a": a, "Tarif": tarif}
		}
	}
}

// Return line of the searched character
function search_current_active_line(car, startL, startC, maxL){
	var final_line = startL;
	for(var i=0; i<maxL; i++){
		var c = javelin.getString(startC, startL+i, 1);
		//log.warning("c:*"+c+"*");
		if(c.compareTo(car) == 0)
			break;
		final_line++;
	}
	return final_line < 11 ? final_line : null;
}

// Searching for '>' of active catclass line or reading from transaction variable
ligne = (ligne != "" && Number(ligne) > 0) ? Number(ligne) : search_current_active_line(">", 5, 4, 6);

// Entry handler for screen class "TarifsDeLocationProgressifs"
function onTarifsDeLocationProgressifsEntry() {
	Tiers = ["Tier  1", "Tier  2", "Tier  3", "Tier  4"];

	table = context.addTextNodeUnderRoot("table", "");

	for(j=0; j<Tiers.length; j++){
		result = searchTier(Tiers[j]);
		if(result){
			row = context.addTextNode(table, "row", "");
			for(key in result){
				context.addTextNode(row, key, result[key]);
			}
		}
	}

     return "skip";
}

