// Cherche la chaine de caractères et qui match les attributs de présentation dans l'écran
// Retourne un objet litéral:
// l => ligne
// c => colonne
// L => longueur de la chaine
// a => code attributs de présentation de la chaine à vérifier
function searchString(str, attr){
	var scrW = javelin.getScreenWidth();
	var scrH = javelin.getScreenHeight();
	var lFound = {"l": -1, "c": -1, "L": -1, "a": -1};
	for ( var i=0; i<scrH; i++ ){
		var line = javelin.getString(0, i, scrW);
		if (line.indexOf(str) != -1){
			var TMPlFound = {"l": i, "c": line.indexOf(str), "L": str.length, "a": attr};
			if(checkStringAttribute(TMPlFound, attr)){
				lFound=TMPlFound;
				TMPlFound=null;
				break;
			}
		}
	}
	return lFound;
}

// Retourne vrai si tous les caractères de la chaine match les attributs de présentation
function checkStringAttribute(o, attr){
	for ( var i=0; i<o.L; i++){
		if ( javelin.getCharAttribute(o.c, o.l) != attr){
			return false;
		}
	}
	return true;
}

// Modifie la valeur de la ligne du Tier correspondant
function changeTierPrice(tierNB, tierValue){
	javelin.moveCursor(searchString("       Tarif", javelin.AT_COLOR_GREEN+javelin.AT_COLOR_BLACK+javelin.AT_UNDERLINE).c, searchString(tiers[tierNB], javelin.AT_COLOR_GREEN+javelin.AT_COLOR_BLACK).l);
    javelin.doAction("KEY_ERASEEOF");
    javelin.send(tierValue);
}

