var arr_tiers = JSON.parse(dataTiers);
var arr_old_tiers = [];
var doMax = 3;

// Cherche la chaine de caracteres dans l'ecran
// Retourne le numero de ligne
function searchString(str, attr){
	var scrW = javelin.getScreenWidth();
	var scrH = javelin.getScreenHeight();
	var str_line = 0;
	var str_col = 0;
	for ( var i=0; i<scrH; i++ ){
		var line = javelin.getString(0, i, scrW);
		if (line.indexOf(str) != -1){
			str_line = i;
			str_col = line.indexOf(str);
			break
		}
	}
	log.warning("line: "+ str_line);
	log.warning("col: "+ str_col);
	return [str_line, str_col];
}

