var curC = 0;
var curL = 0;
var fieldStartC = 0;
var tmpTHD = 70;

// Handles the default screenclass entry event.
function onTransactionDefaultHandlerEntry() {
	context.requestedObject.setDataStableThreshold(tmpTHD);
	log.debug(">>>SET DEFAULT THD:"+context.requestedObject.getDataStableThreshold());
	var doProcess = false;
    curC = javelin.getCurrentColumn();
    curL = javelin.getCurrentLine();
    //log.debug("Cursor position: ["+curC+","+curL+"]");
    var nbFields = javelin.getNumberOfFields();
    //log.debug("#"+nbFields);
    for(var i=0; i<nbFields; i++){
    	if((javelin.getFieldAttribute(i) & javelin.AT_FIELD_PROTECTED) != javelin.AT_FIELD_PROTECTED){
    		doProcess = true;
    		//log.debug("*** Found at least one non protected field ***");
    		break;
    	}
    }
    if(doProcess){
	    for(var i=0; i<nbFields; i++){
	    	//log.debug("C:"+javelin.getFieldColumn(i));
	    	//log.debug("L:"+javelin.getFieldLine(i));
	    	//log.debug("S:"+javelin.getFieldLength(i));
	    	//log.debug("A:0x"+javelin.getFieldAttribute(i).toString(16));
	    	//log.debug("PROTECTED:"+(((javelin.getFieldAttribute(i) & javelin.AT_FIELD_PROTECTED))?"true":"false"));
	    	if(javelin.getFieldLine(i) == curL){
	    		//log.debug("Current Field Line matches current cursor Line ["+javelin.getFieldLine(i)+"]");
	    		if(curC>=javelin.getFieldColumn(i) && curC<=(javelin.getFieldColumn(i)+javelin.getFieldLength(i))){
	    			//log.debug("Current Field Column matches current cursor Column range ["+javelin.getFieldColumn(i)+"<="+curC+"<="+(javelin.getFieldColumn(i)+javelin.getFieldLength(i))+"]");
	    			if((javelin.getFieldAttribute(i) & javelin.AT_FIELD_PROTECTED) == javelin.AT_FIELD_PROTECTED){
	    				//log.debug("*** Forcing cursor focus in a non protected field ***");
				    	javelin.doAction("KEY_TAB");
				    	curC = javelin.getCurrentColumn();
			    		curL = javelin.getCurrentLine();
			    		fieldStartC = curC;
			    	}else{
			    		fieldStartC = javelin.getFieldColumn(i);
			    	}
		    	}
	    	}
	    }
    }
}

// Handles the XML generated event.
function onXmlGenerated() {
	var root = dom.getDocumentElement();
	var xPath = context.getXpathApi();
	var fieldFocus = xPath.selectSingleNode(root, "//*[@hasFocus]");
	if ( fieldFocus == null ) {
		//log.debug("*** No focused block found ***");
		//log.debug("*** Field block attributes are C:"+fieldStartC+", L:"+curL+" ***");
		fieldFocus = xPath.selectSingleNode(root, "//*[@column='"+fieldStartC+"'][@line='"+curL+"']");
		if ( fieldFocus != null ) {
			//log.debug("*** Found block to set focus on ***");
			fieldFocus.setAttribute("hasFocus", "true");
		}
	}
}

