function searchTier(tier){
	_pattern_tier = new RegExp(tier);
	_pattern_tarif = new RegExp("("+tier+")\\s+(\\d+)\\s+(\\d+)\\s+([\\d.]+)");

	sH = javelin.getScreenHeight();
	sW = javelin.getScreenWidth();

	for(i=0; i<sH; i++){
		line = javelin.getString(0, i, sW);
		//log.warning("***"+line+"***");
		if(line.search(_pattern_tier) !== -1){
			log.warning("MATCH FOUND #"+i);
			log.warning("***"+line+"***");
			[, tier, de, a, tarif] = line.match(_pattern_tarif);
			return {"Tier": tier, "de": de, "a": a, "Tarif": tarif}
		}
	}
}

// Entry handler for screen class "TarifsDeLocationProgressifs"
function onTarifsDeLocationProgressifsEntry() {
	Tiers = ["Tier  1", "Tier  2", "Tier  3", "Tier  4", "Tier  5"];

	table = context.addTextNodeUnderRoot("table", "");

	for(j=0; j<Tiers.length; j++){
		result = searchTier(Tiers[j]);
		if(result){
			row = context.addTextNode(table, "row", "");
			for(key in result){
				context.addTextNode(row, key, result[key]);
			}
		}
	}

     return "skip";
}

