dataTiers = JSON.stringify(dataTiers);
//log.warning("==>"+JSON.stringify(dataTiers));

var now = new Date().getTime();
var contextManager = com.twinsoft.convertigo.engine.Engine.theApp.contextManager;

//log.debug(">>>> Context ID => " + context.contextID);
//log.debug(">>>> Context Name => " + context.name);

var ctx = contextManager.get(context.contextID.replace(context.name, "Lox1"));
//log.debug(">>>> Lox1 running? => " + (ctx != null));
if (ctx != null) {
	ctx.lastAccessTime = now;
}

ctx = contextManager.get(context.contextID.replace(context.name, "Lox2"));
//log.debug(">>>> Lox2 running? => " + (ctx != null));
if (ctx != null) {
	ctx.lastAccessTime = now;
}

ctx = contextManager.get(context.contextID.replace(context.name, "Lox3"));
//log.debug(">>>> Lox3 running? => " + (ctx != null));
if (ctx != null) {
	ctx.lastAccessTime = now;
}

var tierPROS = JSON.parse(dataTiers);

var objLen = Object.keys(tierPROS).length;
log.warning(">>>>objLen:"+objLen);
for(var i=0; i<objLen; i++){
	var bSuccess = true;
	var errEl = null
	var tierEl = context.addTextNodeUnderRoot("TIER", "");
	var key = Object.keys(tierPROS)[i];
	context.addTextNode(tierEl, "RANK", tierPROS[key]["tier"]);
	log.warning(">>>>key:"+key);
	if(tierPROS[key]["modify"] === true){
	
		if(parseInt(tierPROS[key]["targetTier"], 10) > parseInt(tierPROS[key]["initPrice"], 10)){
			errEl =  context.addTextNode(tierEl,"ERROR", "");
			context.addTextNode(errEl,"ERR_CODE", -1);
			bSuccess = false;
		}
		
		for(var j=0; j<i; j++){
			if(parseInt(tierPROS[key]["targetTier"], 10) > parseInt(tierPROS[Object.keys(tierPROS)[j]]["targetTier"], 10)){
				errEl =  context.addTextNode(tierEl,"ERROR", "");
				context.addTextNode(errEl,"ERR_CODE", -2);
				context.addTextNode(errEl,"ERR_RANK", j+1);
				bSuccess = false;
			}
		}
		
		/*if((i<objLen-1) && (parseInt(tierPROS[key]["targetTier"], 10) == parseInt(tierPROS[Object.keys(tierPROS)[i+1]]["targetTier"], 10))){
			context.addTextNode(tierEl,"ERR_CODE", -2);
			bSuccess = false;
		}*/
	}
	context.addTextNode(tierEl,"SUCCESS", bSuccess);
}
